import{_ as i,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"33. Workforce Skills Capability And Mobility","description":"","frontmatter":{"title":"33. Workforce Skills Capability And Mobility","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/union-matters/33-workforce-skills-capability-and-mobility.md","filePath":"ebas/has-managers-admin/health-allied-services/union-matters/33-workforce-skills-capability-and-mobility.md"}'),a={name:"ebas/has-managers-admin/health-allied-services/union-matters/33-workforce-skills-capability-and-mobility.md"};function n(s,e,l,p,m,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_33-workforce-skills-capability-and-mobility" tabindex="-1">33. Workforce Skills Capability And Mobility <a class="header-anchor" href="#_33-workforce-skills-capability-and-mobility" aria-label="Permalink to &quot;33. Workforce Skills Capability And Mobility&quot;">​</a></h1><p>This clause does not apply to casual Employees</p><p><strong>33.1</strong> The parties are committed to providing opportunities for Employees to build their skills and capacity and subsequently improve workforce mobility within the classifications provided in this Agreement in accordance with this Clause 33.</p><p><strong>33.2</strong> Workforce Skills, Capability and Mobility Committee</p><p><strong>(a)</strong> Within three months of the commencement of this Agreement, Employers will create a Workforce Skills, Capability and Mobility Committee who will meet quarterly (remotely or in person) and consist of:</p><p><strong>(i)</strong> Representatives of the Employer</p><p><strong>(ii)</strong> HWU delegate and/or representative of the HWU</p><p><strong>(iii)</strong> Where employed by the Employer, the: A. Workplace Trainer/Careers Advisor B. Aboriginal Employment Support Officer C. Disability Employment Support Officer D. Veteran Employment Support Officer</p><p><strong>(iv)</strong> On invitation by the Employer (where applicable/relevant): A. Representatives of local registered training or apprenticeship organisations, B. Representatives of indigenous, disability and/or veteran employment organisations.</p><p><strong>(b)</strong> The terms of reference of the Workforce Skills, Capability and Mobility Committee will include assisting the Employer to:</p><p><strong>(i)</strong> identify current or future skills and capability gaps relevant to the Employer, within the existing workforce,</p><p><strong>(ii)</strong> develop internal pathways within the Employer to improve the skills and capabilities of the existing workforce</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>(iii)</strong> promote foreseeable employment opportunities that require vocational training, with the view to aligning interested Employees with vocational training providers to fulfil these foreseeable employment opportunities</p><p><strong>(iv)</strong> generate partnerships with local registered training and/or apprenticeship organisations</p><p><strong>(v)</strong> generate partnerships with local indigenous, disability and/or veteran employment organisations</p><p><strong>(vi)</strong> any other matter agreed locally by the Workforce Skills, Capability and Mobility Committee</p><p><strong>(c)</strong> The Workforce Skills, Capability and Mobility Committee may meet as scheduled meetings with the HWU as agreed locally.</p><p>PART I – CLASSIFICATION AND STAFFING</p><p>Plain language terms: skills, mobility.</p>',20)])])}const h=i(a,[["render",n]]);export{y as __pageData,h as default};
